    22→import java.util.Map;
    23→import java.util.Timer;
    24→import java.util.concurrent.ConcurrentHashMap;
    25→import java.util.concurrent.atomic.AtomicInteger;
    26→
    27→import org.apache.camel.Endpoint;
    28→import org.apache.camel.api.management.ManagedAttribute;
    29→import org.apache.camel.spi.Metadata;
    30→import org.apache.camel.support.DefaultComponent;
    31→
    32→/**
    33→ * The <a href="http://camel.apache.org/timer.html">Timer Component</a> is for generating message exchanges when a timer
    34→ * fires.
    35→ *
    36→ * Represents the component that manages {@link TimerEndpoint}. It holds the list of {@link TimerConsumer} objects that
    37→ * are started.
    38→ */
    39→@org.apache.camel.spi.annotations.Component("timer")
    40→public class TimerComponent extends DefaultComponent {
    41→    private final Map<String, TimerHolder> timers = new ConcurrentHashMap<>();
    42→
    43→    @Metadata
    44→    private boolean includeMetadata;
    45→
    46→    public TimerComponent() {
    47→    }
    48→
    49→    @ManagedAttribute(description = "Include metadata")
    50→    public boolean isIncludeMetadata() {
    51→        return includeMetadata;
    52→    }
    53→
    54→    /**
    55→     * Whether to include metadata in the exchange such as fired time, timer name, timer count etc.
    56→     */
    57→    @ManagedAttribute(description = "Include metadata")
    58→    public void setIncludeMetadata(boolean includeMetadata) {
    59→        this.includeMetadata = includeMetadata;
    60→    }
    61→
    62→    public Timer getTimer(TimerConsumer consumer) {
    63→        String key = consumer.getEndpoint().getTimerName();
    64→        if (!consumer.getEndpoint().isDaemon()) {
    65→            key = "nonDaemon:" + key;
    66→        }
    67→
    68→        return timers.compute(key, (k, v) -> {
    69→            if (v == null) {
    70→                // the timer name is also the thread name, so lets resolve a name to be used
    71→                String name = consumer.getEndpoint().getCamelContext().getExecutorServiceManager()
    72→                        .resolveThreadName("timer://" + consumer.getEndpoint().getTimerName());
    73→                return new TimerHolder(new Timer(name, consumer.getEndpoint().isDaemon()));
    74→            }
    75→            v.refCount.incrementAndGet();
    76→            return v;
    77→        }).timer;
    78→    }
    79→
    80→    public void removeTimer(TimerConsumer consumer) {
    81→        String key = consumer.getEndpoint().getTimerName();
    82→        if (!consumer.getEndpoint().isDaemon()) {
    83→            key = "nonDaemon:" + key;
    84→        }
    85→        timers.computeIfPresent(key, (k, v) -> {
    86→            if (v.refCount.decrementAndGet() == 0) {
    87→                v.timer.cancel();
    88→                return null;
    89→            }
    90→            return v;
    91→        });
    92→    }
    93→
    94→    @Override
    95→    protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
    96→        TimerEndpoint answer = new TimerEndpoint(uri, this, remaining);
    97→        answer.setIncludeMetadata(includeMetadata);
    98→
    99→        // convert time from String to a java.util.Date using the supported patterns
   100→        String time = getAndRemoveOrResolveReferenceParameter(parameters, "time", String.class);
   101→        String pattern = getAndRemoveOrResolveReferenceParameter(parameters, "pattern", String.class);
   102→        if (time != null) {
   103→            SimpleDateFormat sdf;
   104→            if (pattern != null) {
   105→                sdf = new SimpleDateFormat(pattern);
   106→            } else if (time.contains("T")) {
   107→                sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss");
   108→            } else {
   109→                sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
   110→            }
   111→            Date date = sdf.parse(time);
   112→            answer.setTime(date);
   113→            answer.setPattern(pattern);
   114→        }
   115→
   116→        setProperties(answer, parameters);
   117→        return answer;
   118→    }
   119→
   120→    @Override
   121→    protected void doStop() throws Exception {
   122→        Collection<TimerHolder> collection = timers.values();
   123→        for (TimerHolder holder : collection) {
   124→            holder.timer.cancel();
   125→        }
   126→        timers.clear();
   127→    }
   128→
   129→    private static class TimerHolder {
   130→        private final Timer timer;
   131→        private final AtomicInteger refCount;
   132→
   133→        private TimerHolder(Timer timer) {
   134→            this.timer = timer;
   135→            this.refCount = new AtomicInteger(1);
   136→        }
   137→    }
   138→}
